// Parse the SSE-framed reply; nag only if a gate is still open/in_progress.
const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'tool error');
const gates = JSON.parse(rpc.result?.content?.[0]?.text ?? '[]');
const open = (Array.isArray(gates) ? gates : []).filter((g) => g.status === 'open' || g.status === 'in_progress');
if (open.length === 0) return []; // all clear -> stop
const keys = open.map((g) => `${g.key}:${g.status}`);
return [{ json: { count: open.length, keys } }];

const raw = $input.first().json.data ?? $input.first().json.body ?? '';
const line = String(raw).split('\n').find((l) => l.startsWith('data:')) ?? '';
const rpc = JSON.parse(line.slice(5).trim());
if (rpc.result?.isError) throw new Error(rpc.result.content?.[0]?.text ?? 'notify failed');
return [{ json: { ok: true } }];
